  ('clan-hub', 'links', $json${"links":[{"id":"tomato","title":"Tomato.gg","url":"https://tomato.gg","category":"stats","description":"Stats joueurs, performances par char, WN8, Marks of Excellence.","tags":["stats","wn8","moe"]},{"id":"wotlabs","title":"WoTLabs","url":"https://wotlabs.net","category":"stats","description":"Statistiques détaillées et progression récente des joueurs.","tags":["stats","recent","progression"]},{"id":"tanks-gg","title":"Tanks.gg","url":"https://tanks.gg","category":"comparaison","description":"Comparaison de chars, modèles 3D, blindage, DPM, zones faibles.","tags":["comparaison","blindage","3d"]},{"id":"armor-inspector","title":"Armor Inspector","url":"https://armor.wotinspector.com","category":"blindage","description":"Visionneuse de blindage interactive avec zones de pénétration.","tags":["blindage","pénétration","zones-faibles"]},{"id":"wot-portal","title":"Portail WoT EU","url":"https://worldoftanks.eu","category":"officiel","description":"Actualités officielles Wargaming EU, événements, mises à jour.","tags":["officiel","actualités","wargaming"]},{"id":"wot-globalmap","title":"Carte globale WoT","url":"https://eu.wargaming.net/globalmap/","category":"clan","description":"Carte globale pour les Clan Wars — territoires, positions, batailles.","tags":["cw","map","territoire"]},{"id":"wot-clans","title":"Portail des Clans WoT","url":"https://eu.wargaming.net/clans/wot/","category":"clan","description":"Profil des clans, classements, recherche de membres.","tags":["clan","classement","membres"]},{"id":"skill4ltu","title":"Skill4ltu — Guides YouTube","url":"https://www.youtube.com/@skill4ltu","category":"interne","description":"Le meilleur joueur compétitif EU. Guides de gameplay et reviews de chars.","tags":["youtube","guide","gameplay"]},{"id":"wot-wiki","title":"WoT Wiki EU","url":"https://wiki.wargaming.net/fr/World_of_Tanks","category":"officiel","description":"Wiki officiel : mécaniques de jeu, chars, historique, mises à jour.","tags":["wiki","officiel","mécaniques"]},{"id":"wotconsole-map","title":"WoT Maps — Overview","url":"https://www.vbaddict.net/maps.php","category":"maps","description":"Aperçu des cartes WoT avec positions populaires.","tags":["maps","positions"]}]}$json$::jsonb)
  on conflict (page_slug, content_key) do nothing;

insert into public.clan_page_content (page_slug, content_key, payload) values
  ('clan-hub', 'maps', $json${"maps":[{"slug":"prokhorovka","name":"Prokhorovka","modes":["cw","bastion","offensive"],"priority":"prioritaire","map_type":"vision","spawn_a":[{"name":"Colline centrale","role":"MT/LT — prise de vision","notes":"Position clé pour contrôler la moitié de la carte"},{"name":"Flanc train","role":"TD sniper / couverture","notes":"Couvre les rushes sur les voies ferrées"}],"spawn_b":[{"name":"Contre-colline","role":"MT/HT — pression","notes":"Répond à l'occupation de la colline ennemie"},{"name":"Flanc droite","role":"LT/MT — flanquer et reset","notes":"Possibilité de reset rapide depuis ce flanc"}],"recommended_roles":["Light actif","Medium flex","TD sniper"],"recommended_tanks":["EBR 105","CS-63","Strv 103B","Object 277"],"strat_simple":"Prendre la colline avec 2-3 chars et tenir. TDs couvrent les voies depuis les buissons. LT spot les mouvements ennemis.","strat_advanced":"Sacrifice scout en début de game + rush train T2 avec les mediums pour couper le retour ennemi pendant que les heavies poussent la colline.","common_mistakes":["Partir seul sur la colline avant 30 secondes.","Ignorer le flanc train en mid-game.","Ne pas spotter les positions TD ennemis avant d'avancer."],"caller_notes":"Préparer deux compos : vitesse pour colline, sniper pour train. EBR est essentiel sur cette carte.","tags":["vision","colline","train","sniper"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"himmelsdorf","name":"Himmelsdorf","modes":["bastion","cw"],"priority":"utile","map_type":"urbaine","spawn_a":[{"name":"Colline","role":"HT hulldown — position dominante","notes":"Contrôle la majorité de la carte depuis le dessus"},{"name":"Rue principale","role":"HT push — siège urbain","notes":"Ligne directe mais dangereuse"}],"spawn_b":[{"name":"Contre-colline","role":"HT — répondre à la colline ennemie"},{"name":"Flanc gauche","role":"MT — flanquer via les ruelles"}],"recommended_roles":["Heavy push","Heavy hulldown","TD assault"],"recommended_tanks":["Super Conqueror","60TP","T110E3"],"strat_simple":"Prendre la colline avec les HT les plus rapides. TDs tiennent la rue. MTs flanquent par les ruelles.","strat_advanced":"Double push : colline + rue simultanément pour saturer la défense ennemie.","common_mistakes":["Aller dans la rue sans couverture colline.","Ignorer les ruelles — les mediums ennemis peuvent flanquer."],"caller_notes":"Colline = priorité absolue. Qui tient la colline tient la carte.","tags":["urbain","colline","couloir","hulldown"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"mines","name":"Mines","modes":["bastion","cw"],"priority":"utile","map_type":"push","spawn_a":[{"name":"Île centrale","role":"HT/MT — contrôle central","notes":"Prendre l'île = avantage massif"},{"name":"Flanc gauche","role":"TD / support"}],"spawn_b":[{"name":"Colline","role":"HT hulldown — domine l'île"},{"name":"Flanc droit","role":"MT — flanquer depuis la plage"}],"recommended_roles":["Heavy hulldown","Medium flex","Light actif"],"recommended_tanks":["Super Conqueror","Object 277","EBR 105"],"strat_simple":"Race vers l'île ou la colline selon le spawn. L'équipe qui contrôle le centre gagne.","strat_advanced":"Feinte île + rush colline avec les chars les plus rapides pendant que l'ennemi va vers l'île.","common_mistakes":["Hésiter sur l'île — il faut décider vite.","Négliger la colline quand l'ennemi l'a."],"caller_notes":"Décision en 10 secondes : île ou colline ? Les deux en même temps est risqué.","tags":["île","central","race","push"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"}]}$json$::jsonb)
  on conflict (page_slug, content_key) do nothing;

insert into public.clan_page_content (page_slug, content_key, payload) values
  ('clan-hub', 'roles', $json${"roles":[{"slug":"heavy-push","title":"Heavy push","icon":"ArrowRight","summary":"Forcer l'entrée dans une zone, briser une ligne ennemie, imposer le combat au contact.","mission":"Aller chercher l'ennemi, forcer les engagements et créer de l'espace pour les alliés.","priorities":["Avancer avec le soutien allié — jamais seul.","Trader favorablement : te faire toucher si l'allié derrière toi peut tirer aussi.","Annoncer tes mouvements au caller avant de push.","Garder assez de HP pour le mid-game."],"mistakes":["Push seul sans vérifier que les alliés sont derrière.","Rester bloqué à cause d'un TD caché — appelle le caller.","Exposer son lower plate inutilement."],"positioning":"En tête de colonne, derrière une couverture, prêt à avancer.","hp_management":"Tu peux \"donner\" des HP si les alliés en profitent. Ne jamais perdre des HP gratuitement.","timing":"Push dès que le caller l'annonce — le timing coordonné est clé.","example_tanks":["Object 277","IS-7","60TP","BZ-75"],"modes":["cw","bastion","offensive"],"tags":["push","contact","assault"],"updated_at":"Juin 2026"},{"slug":"heavy-hulldown","title":"Heavy hulldown","icon":"Shield","summary":"Tenir une position clé, absorber les dégâts, bloquer un couloir.","mission":"Être le mur que l'ennemi ne peut pas traverser depuis une position hulldown.","priorities":["Trouver la position parfaite avant que le fight commence.","Ne montrer que la coupole — jamais le hull.","Absorber pour permettre aux alliés derrière de tirer."],"mistakes":["Exposer son hull par impatience.","Abandonner une bonne position trop tôt.","Se repositionner sans raison valable."],"positioning":"Position surélevée ou en crête, hull caché, coupole exposée seulement.","hp_management":"Priorité absolue à la survie — chaque HP compte pour tenir la position.","timing":"En place avant l'ennemi. Anticiper où le fight va avoir lieu.","example_tanks":["Super Conqueror","T110E5"],"modes":["cw","bastion"],"tags":["hulldown","défensif","anchor","coupole"],"updated_at":"Juin 2026"},{"slug":"medium-flex","title":"Medium flex","icon":"Zap","summary":"Créer des décalages, flanker, soutenir les pushes et assurer les rotations.","mission":"Être là où l'ennemi ne t'attend pas. Créer des opportunités pour les alliés.","priorities":["Lire la minimap en permanence.","Ne pas perdre ses HP gratuitement en début de game.","Créer du crossfire sur les cibles engagées par les alliés.","Revenir défendre ou reset si nécessaire."],"mistakes":["Jouer comme un heavy — tu n'as pas le blindage.","Rester bloqué sur une ligne morte.","Flanker sans information préalable.","Arriver trop tard sur les rotations."],"positioning":"Positions intermédiaires avec plusieurs options de sortie.","hp_management":"Garder un maximum de HP pour le late-game où les flexers font la différence.","timing":"Intervenir au bon moment — ni trop tôt (avant d'avoir l'info) ni trop tard.","example_tanks":["CS-63","T110E5"],"modes":["cw","bastion","offensive","peloton"],"tags":["flex","rotation","crossfire","mobile"],"updated_at":"Juin 2026"},{"slug":"medium-sniper","title":"Medium sniper","icon":"Crosshair","summary":"Support feu à longue portée, punir les chars exposés, couvrir les flancs.","mission":"Infliger des dégâts à distance tout en restant difficile à toucher.","priorities":["Identifier les cibles exposées à longue portée.","Tirer et repositionner — jamais rester fixe après un tir.","Couvrir les avances des alliés."],"mistakes":["Engager à courte distance sans blindage suffisant.","Rester sur la même position trop longtemps."],"positioning":"Positions élevées ou offrant une bonne ligne de vue avec couverture partielle.","hp_management":"Éviter de prendre des dégâts — tu n'as pas le blindage pour trader.","timing":"Attendre que les alliés fixent l'ennemi avant de tirer.","example_tanks":["Leopard 1"],"modes":["cw","bastion","random"],"tags":["sniper","précision","longue-portée"],"updated_at":"Juin 2026"},{"slug":"light-actif","title":"Light scout actif","icon":"Eye","summary":"Prise d'information rapide, reset de cap, pression sur les flancs.","mission":"Donner les informations dont le caller a besoin pour décider.","priorities":["Spotter les positions ennemies dès le début.","Survivre — tu vaux plus vivant qu'en tentant des dégâts.","Annoncer les infos de vision : position, HP estimé, direction.","Reset le cap si demandé."],"mistakes":["Mourir pour des dégâts inutiles.","Ne pas annoncer les infos de vision.","Rester bloqué sur une position sans utilité."],"positioning":"Flancs, buissons, positions avec vision sur les axes ennemis.","hp_management":"Priorité absolue à la survie. Fuir immédiatement si menacé.","timing":"Spotter en début de game — les 30 premières secondes sont cruciales.","example_tanks":["EBR 105"],"modes":["cw","bastion","offensive"],"tags":["scout","vision","info","wheeled"],"updated_at":"Juin 2026"},{"slug":"td-sniper","title":"TD sniper","icon":"Target","summary":"Punir les avances ennemies depuis les positions arrière, contrôler les distances.","mission":"Tuer à distance tout ce qui ose avancer sans couverture.","priorities":["Prendre les positions élevées avec large ligne de vue.","Ne jamais s'exposer en flanc.","Se repositionner régulièrement pour éviter le counter.","Annoncer les kills et les HP ennemis."],"mistakes":["Engager à courte distance — tu n'as pas de tourelle.","Rester trop longtemps sur la même position.","Avancer alors que tu devrais couvrir."],"positioning":"Fond de map, positions élevées, lignes de vue longues.","hp_management":"Garder un maximum de HP — tu ne devrais pas en prendre.","timing":"Tirer quand les alliés fixent l'attention — jamais le premier à te révéler.","example_tanks":["Strv 103B"],"modes":["cw","bastion"],"tags":["sniper","camouflage","TD","distance"],"updated_at":"Juin 2026"},{"slug":"td-assault","title":"TD d'assaut","icon":"Flame","summary":"Avancer dans des couloirs protégés par un blindage frontal massif.","mission":"Être la pointe blindée dans les couloirs ou zones urbaines.","priorities":["Ne montrer que le blindage frontal.","Avancer lentement et méthodiquement.","Tenir une zone pour les alliés derrière."],"mistakes":["S'exposer en flanc — un seul tir latéral peut être fatal.","Jouer sur des cartes ouvertes sans couverture."],"positioning":"Couloirs étroits, zones urbaines, n'importe où les flancs sont protégés.","hp_management":"Ton blindage frontal te protège — utilise-le au maximum.","timing":"Avancer quand les alliés ont éliminé les menaces latérales.","example_tanks":["T110E3"],"modes":["bastion","cw"],"tags":["TD","assault","blindage","couloir"],"updated_at":"Juin 2026"},{"slug":"autoloader","title":"Support autoloader","icon":"Layers","summary":"Infliger des rafales de dégâts décisives sur des cibles affaiblies.","mission":"Vider un chargeur complet sur la cible prioritaire annoncée par le caller.","priorities":["Garder le chargeur plein pour les moments clés.","Viser les cibles affaiblies — maximiser l'efficacité du burst.","Se mettre en sécurité pour recharger."],"mistakes":["Gaspiller les obus en early game.","Rester visible pendant le rechargement complet.","Engager un char full HP seul."],"positioning":"Derrière les alliés, en attente d'opportunités.","hp_management":"Éviter les confrontations directes — ton rechargement te rend vulnérable.","timing":"Frapper quand le caller désigne une cible affaiblie ou en difficulté.","example_tanks":["Vz. 55","TVP T 50/51"],"modes":["cw","bastion","offensive","peloton"],"tags":["autoloader","burst","timing"],"updated_at":"Juin 2026"}]}$json$::jsonb)
  on conflict (page_slug, content_key) do nothing;

insert into public.clan_page_content (page_slug, content_key, payload) values
  ('clan-hub', 'strategies', $json${"strategies":[{"slug":"focus-fire","title":"Focus fire","category":"focus-fire","modes":["cw","bastion","offensive"],"tags":["priorité","cible","caller"],"summary":"Concentrer tous les tirs sur la même cible pour éliminer rapidement les canons ennemis.","rules":["Le caller annonce la cible — tout le monde tape dessus.","Les cibles à un tir sont prioritaires.","On ne change pas de cible sans ordre du caller.","Même si tu peux tirer sur quelqu'un d'autre, tu attends."],"example":"Le caller annonce \"Focus 60TP flanc gauche\". Tous les chars disponibles tirent sur le 60TP jusqu'à sa destruction, même si un IS-7 est à portée.","common_mistakes":["Chaque joueur tire sur une cible différente — l'ennemi garde tous ses canons actifs.","Changer de cible parce qu'on \"voit mieux\" un autre char.","Ne pas écouter le caller et viser la cible la plus proche."],"caller_phrase":"\"Focus le 60TP flanc gauche, on le sort maintenant.\"","player_actions":["Écoute et identifie la cible annoncée.","Tire sur cette cible uniquement.","Annonce si tu peux pas la voir."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"push-groupe","title":"Push groupé","category":"push","modes":["cw","bastion","offensive"],"tags":["push","timing","coordonné"],"summary":"Avancer ensemble en simultané pour saturer la défense ennemie.","rules":["Tout le monde bouge au même moment — le signal vient du caller.","Les heavies sont en tête, les mediums et TDs couvrent.","Pas de flâneurs — si un char n'avance pas, le push échoue.","Maintenir la pression : pas de stop au milieu du push."],"example":"Le caller annonce \"Push flanc droit dans 5 secondes\". 5 chars avancent ensemble, les TDs tiennent le flanc gauche, le push prend la position avant que l'ennemi puisse réorienter.","common_mistakes":["Un char s'arrête en cours de route — le push est bloqué.","Les soutiens n'avancent pas et laissent le push sans protection.","Push trop tôt ou trop tard par rapport au signal."],"caller_phrase":"\"Push flanc droit avec moi — 3, 2, 1, GO.\"","player_actions":["Écouter le compte à rebours.","Avancer au signal — pas avant, pas après.","Garder la formation."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"trade-positif","title":"Trade positif","category":"trade","modes":["cw","bastion","offensive","peloton"],"tags":["hp","trade","efficacité"],"summary":"Échanger des HP de manière favorable : donner 400 pour prendre 400, ou mieux.","rules":["Tirer seulement si l'échange est favorable (même alpha ou plus).","Si ton alpha est plus bas, trades seulement avec couverture rapide.","Trader pour permettre à un allié avec plus d'alpha de tirer après toi.","Ne jamais prendre 2 tirs pour en donner 1."],"example":"Un Object 277 et un IS-4 ennemi sont dans un couloir. L'Object 277 peek pour prendre un tir et fixer l'IS-4, pendant que le 60TP derrière tire sans se faire toucher.","common_mistakes":["Rester exposé et prendre 2 ou 3 tirs pour en donner 1.","Trader des HP sans avantage tactique derrière.","Laisser un allié faire tous les échanges défavorables seul."],"caller_phrase":"\"Trade favorable — peek, il va te tirer, puis recouvre.\"","player_actions":["Peek rapidement, tirer, reprendre couverture.","Calculer l'échange avant de bouger.","Annoncer si tu prends trop de dégâts."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"rotation-rapide","title":"Rotation rapide","category":"rotation","modes":["cw","bastion","offensive"],"tags":["rotation","flexibilité","timing"],"summary":"Déplacer des chars d'un flanc à l'autre pour répondre à une menace ou créer une opportunité.","rules":["La rotation se fait avant que le flanc soit perdu.","Les chars les plus rapides (mediums, lights) rotent en premier.","Annoncer \"je rote\" pour que le caller suive les positions.","Ne pas abandonner une position clé sans ordre du caller."],"example":"Le flanc gauche est stabilisé, mais le flanc droit est sous pression. Le caller envoie les 2 mediums sur la droite pour contre-attaquer avant que l'ennemi prenne la position.","common_mistakes":["Rester trop longtemps sur un flanc mort.","Roten trop tard — l'ennemi a déjà la position.","Partir sans annoncer."],"caller_phrase":"\"CS-63 et EBR, rotez flanc droit, vite.\"","player_actions":["Partir immédiatement à l'annonce.","Prendre le chemin le plus court.","Annoncer quand tu arrives sur la nouvelle position."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"discipline-vocale","title":"Discipline vocale","category":"vocal","modes":["cw","bastion","offensive"],"tags":["communication","vocal","discipline"],"summary":"Maintenir un canal vocal utile et calme pour que le caller puisse décider efficacement.","rules":["Micro en sourdine si tu n'as rien d'utile à dire.","Annoncer uniquement les infos utiles : positions, HP, cap, mort d'un ennemi.","Pas de discussions off-topic pendant la game.","Pas de \"bg\", \"noob\" ou commentaires négatifs.","Si tu veux parler, attends un moment calme ou demande la parole."],"example":"\"T 100 LT flanc droit, 400 HP\" — voilà une info utile. \"Nul ce char\" — pas utile.","common_mistakes":["Parler trop — le caller ne peut plus entendre les infos importantes.","Débattre d'un call pendant la game.","Commentaires négatifs qui désorganisent le moral de l'équipe."],"caller_phrase":"\"Vocal utile uniquement — on écoute les calls.\"","player_actions":["Micro en sourdine par défaut.","Parler uniquement pour des infos tactiques.","Garder le calme quoi qu'il arrive."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"gestion-hp","title":"Gestion des HP","category":"hp","modes":["cw","bastion","offensive","peloton","random"],"tags":["hp","survie","économie"],"summary":"Garder le maximum de HP pour les moments où ils ont de la valeur.","rules":["Ne jamais prendre de dégâts inutiles — chaque HP compte.","Les chars mobiles gardent leurs HP pour les rotations ou reset.","Les anchors et heavies peuvent \"investir\" des HP si ça débloquer quelque chose.","Un char mort ne peut plus avoir d'impact — la survie est toujours la priorité."],"example":"Un EBR 105 à 800 HP vaut beaucoup plus qu'un EBR à 100 HP même s'il a spotté toute la game. Garder ses HP permet de reset le cap ou fuir si nécessaire.","common_mistakes":["Prendre des dégâts pour \"des stats\" en fin de game.","Rester exposé après un tir reçu au lieu de se couvrir.","Partir chercher des dégâts alors que la base est menacée."],"caller_phrase":"\"Préserve tes HP — tu seras utile pour le finish.\"","player_actions":["Peek, tirer, reculer systématiquement.","Signaler son niveau de HP si bas.","Ne jamais rester à découvert inutilement."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"reset-base","title":"Reset de base","category":"reset","modes":["cw","bastion","offensive"],"tags":["cap","reset","urgence"],"summary":"Empêcher l'ennemi de capturer la base en y retournant à temps.","rules":["Annoncer le cap immédiatement quand tu le vois.","Les LT et MT partent en reset — les heavies restent en fight si possible.","Un seul char sur le cap suffit souvent pour reset si l'ennemi est seul.","Reset avant le finish — ne pas attendre la dernière seconde."],"example":"EBR ennemi commence à capper. Le EBR allié part immédiatement le reset, pendant que les autres chars continuent le fight principal sans se disperser.","common_mistakes":["Tout le monde part reset — personne ne tient le fight principal.","Reset trop tard — le cap est fini.","Un heavy lent part reset à la place d'un char mobile."],"caller_phrase":"\"CAP — EBR et CS-63 en reset, le reste tient le flanc.\"","player_actions":["Partir immédiatement si tu es désigné.","Annoncer quand tu es sur le cap.","Rester le temps de reset complètement."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"crossfire","title":"Crossfire","category":"crossfire","modes":["cw","bastion","offensive","peloton"],"tags":["angle","pression","tactique"],"summary":"Créer deux angles de tir différents pour que l'ennemi ne puisse pas se couvrir des deux.","rules":["Un char fixe l'ennemi frontalement, un autre prend un angle latéral.","L'ennemi doit choisir — il prend des dégâts d'un côté ou de l'autre.","La communication est clé : \"je suis en angle droit, fixe-le\".","Ne pas exposer deux chars au même TD ennemi."],"example":"Un Object 277 fixe un IS-4 depuis le frontal. Un CS-63 contourne par la droite. L'IS-4 doit choisir : perdre des HP du 277 ou se retourner pour le CS-63.","common_mistakes":["Les deux chars prennent le même angle — pas de crossfire.","Le char censé fixer recule au lieu de tenir.","Exposer les deux chars à un TD ennemi en même temps."],"caller_phrase":"\"CS-63, prends l'angle droit — le 277 le fixe frontalement.\"","player_actions":["Confirmer ta position au caller.","Rester en position de fixing même si tu prends des dégâts.","Tirer dès que l'angle est disponible."],"validated_by":"Staff ATFR","updated_at":"Juin 2026"}]}$json$::jsonb)
  on conflict (page_slug, content_key) do nothing;

insert into public.clan_page_content (page_slug, content_key, payload) values
  ('clan-hub', 'tanks', $json${"tanks":[{"slug":"object-277","name":"Object 277","nation":"urss","tier":10,"class":"HT","clan_priority":"prioritaire","modes":["cw","bastion","offensive","peloton"],"role_in_battle":"Heavy mobile / Flanker / Push rapide","gameplay_type":"Agressif — prise de position rapide","summary":"Heavy d'assaut mobile. Excellent pour dicter le tempo, prendre les positions fortes et soutenir les pushes. La meilleure mobilité de sa classe.","equipments":[{"name":"Durcissement amélioré","reason":"Améliore la survie et la résistance aux dégâts"},{"name":"Fouloir amélioré","reason":"Augmente les DPS"},{"name":"Stabilisateur vertical","reason":"Indispensable pour tirer en mouvement"}],"alt_equipments":[{"name":"Turbo","reason":"Maximalise la mobilité pour les rotations rapides"},{"name":"Fouloir amélioré"},{"name":"Stabilisateur vertical"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Râtelier sécurisé","priority":3},{"name":"Précision (commandant)","priority":4},{"name":"Conduite souple","priority":5}],"consumables":["Grande trousse de premiers secours","Grande trousse de réparation","Essence 100 octanes"],"ammo_setup":"2/3 AP + 1/3 HEAT. Éviter les obus HE sauf cas spécifique.","do_list":["Suivre les calls immédiatement — tu es rapide, profite-en.","Trader avec les alliés en difficulté.","Prendre les angles à l'avantage et reculer avant d'être one-shot.","Garder assez de HP pour le mid et late game.","Utiliser ta mobilité pour créer des crossfires."],"dont_list":["Partir seul en début de game.","Camper en fond de map — tu n'es pas un TD.","Peek sans soutien allié.","Perdre tes HP dans des fights inutiles en early."],"tags":["push","mobile","trade","rotation","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"cs-63","name":"CS-63","nation":"pologne","tier":10,"class":"MT","clan_priority":"prioritaire","modes":["cw","bastion","offensive","peloton"],"role_in_battle":"Medium flex / Flank sniper / Rotation rapide","gameplay_type":"Hybride — snipe puis agression à moyenne portée","summary":"Medium ultra-mobile grâce au boost. Capable de passer d'un flanc à l'autre en quelques secondes. Idéal pour répondre aux situations, flanker les chars isolés et assurer les rotations rapides.","equipments":[{"name":"Stabilisateur vertical","reason":"Tir en mouvement avec le boost"},{"name":"Fouloir amélioré"},{"name":"Visée renforcée","reason":"Améliore la précision cruciale pour ce char"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Précision (commandant)","priority":3},{"name":"Conduite souple","priority":4}],"consumables":["Grande trousse","Grande réparation","Turbo manuel"],"do_list":["Utiliser le boost pour les rotations et les escapes.","Ne pas engager frontalement — tu n'es pas un heavy.","Flanker les chars isolés ou absorbés par d'autres fights.","Revenir défendre si la base est en danger."],"dont_list":["Utiliser le boost inutilement au début — garde-le pour fuir ou attaquer.","Engager sans sortie possible.","Ignorer la minimap."],"tags":["flex","rotation","mobile","boost","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"ebr-105","name":"EBR 105","nation":"france","tier":10,"class":"LT","clan_priority":"prioritaire","modes":["cw","bastion","offensive"],"role_in_battle":"Scout actif / Spotter / Reset de base","gameplay_type":"Support vision — mobilité maximale, dégâts secondaires","summary":"Scout le plus rapide du jeu. Essentiel en CW pour la prise d'information, le spotting des positions ennemies, les resets de cap et la création de pression sur les flancs ouverts.","equipments":[{"name":"Optique de combat","reason":"Améliore la portée de vision"},{"name":"Stabilisateur vertical"},{"name":"Ventilation améliorée","reason":"Boost général des capacités"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Camouflage","priority":2},{"name":"Maître des réparations","priority":3},{"name":"Œil de lynx (commandant)","priority":4}],"consumables":["Grande trousse","Grande réparation","Eau de source"],"do_list":["Spotter les positions dès le début.","Annoncer les infos de vision au caller.","Reset le cap quand demandé.","Eviter les engagements directs sauf si tu es sûr de te tirer."],"dont_list":["Mourir en début de game — ta valeur est dans ta mobilité.","Aller chercher des dégâts au lieu de spotter.","Longer les côtés au lieu de fournir de l'info centrale."],"tags":["scout","vision","reset","wheeled","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"super-conqueror","name":"Super Conqueror","nation":"gb","tier":10,"class":"HT","clan_priority":"prioritaire","modes":["cw","bastion","offensive","peloton"],"role_in_battle":"Heavy hulldown / Anchor défensif","gameplay_type":"Défensif/Hulldown — tient une position, bloque un couloir","summary":"Meilleur hulldown du jeu avec sa coupole quasi-indestructible. S'il prend une bonne position, il peut tenir contre 3 ou 4 tanks. Indispensable pour bloquer des couloirs ou tenir une zone clé.","equipments":[{"name":"Durcissement amélioré"},{"name":"Fouloir amélioré"},{"name":"Visée renforcée","reason":"Améliore le temps de visée depuis la coupole"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Surdité (conducteur)","priority":3},{"name":"Précision (commandant)","priority":4}],"consumables":["Grande trousse x2","Grande réparation","Extinction automatique"],"do_list":["Trouver la position hulldown parfaite avant le fight.","Ne montrer que la coupole — le hull est pénétrable.","Tenir une position face à plusieurs ennemis si possible.","Absorber les dégâts pour permettre aux alliés de pousser."],"dont_list":["Exposer son hull.","Bouger sans raison valable depuis une bonne position.","Jouer comme un char mobile — il n'est pas rapide."],"tags":["hulldown","anchor","defensif","coupole","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"60tp","name":"60TP Lewandowskiego","nation":"pologne","tier":10,"class":"HT","clan_priority":"prioritaire","modes":["cw","bastion","offensive","peloton"],"role_in_battle":"Heavy siège / One-shot machine","gameplay_type":"Agressif au contact — dégâts bruts extrêmes","summary":"Le canon le plus puissant en tier 10. Alpha de 750 HP par coup. Idéal pour sortir les cibles affaiblies et dominer en siège. Un one-shot bien placé peut changer une game.","equipments":[{"name":"Durcissement amélioré"},{"name":"Fouloir amélioré"},{"name":"Stabilisateur vertical"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Châssis lubrifié","priority":3}],"consumables":["Grande trousse","Grande réparation","Essence 100 octanes"],"ammo_setup":"AP premium + HE en backup pour chars fragiles","do_list":["Annoncer \"one shot\" quand une cible est à portée.","Trader favorablement : ton alpha vaut le coup même si tu prends du retour.","Prioriser les targets affaiblies pour maximiser l'efficacité."],"dont_list":["Gaspiller des tirs sur des cibles à pleine santé en échange mauvais.","T'approcher d'un hulldown solide — tu n'es pas fait pour ça.","Sniper depuis le fond — ce n'est pas ton rôle."],"tags":["siège","one-shot","alpha","push","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"is-7","name":"IS-7","nation":"urss","tier":10,"class":"HT","clan_priority":"utile","modes":["cw","bastion","peloton","random"],"role_in_battle":"Heavy push / Brise-siège","gameplay_type":"Agressif — rampe, absorbe, push","summary":"Excellent pour forcer des engagements et briser des lignes. Blindage de caisse très bien incliné. Moins performant que l'Object 277 en mobilité pure, mais plus solide en frontal.","equipments":[{"name":"Stabilisateur vertical"},{"name":"Fouloir amélioré"},{"name":"Durcissement amélioré"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Conduite souple","priority":3}],"consumables":["Grande trousse","Grande réparation","Essence 100 octanes"],"do_list":["Ramper vers les ennemis en utilisant le blindage incliné.","Push les positions dures avec du soutien allié.","Utiliser la mobilité pour changer de flanc si nécessaire."],"dont_list":["Exposer ton blindage de coupole — il est faible.","Sniper — ce n'est pas ton rôle.","Jouer sans soutien immédiat."],"tags":["push","blindage","rampe","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"e-100","name":"E 100","nation":"allemagne","tier":10,"class":"HT","clan_priority":"utile","modes":["cw","bastion","peloton"],"role_in_battle":"Heavy siège / Absorbeur de dégâts","gameplay_type":"Siège et pression — trade favorable, hold line","summary":"Énorme masse à l'avant. Trade bien grâce à son alpha de 750. Son hull est pénétrable, mais son volume impose le respect. Utilisé pour bloquer et soutenir les pushes par sa masse.","equipments":[{"name":"Durcissement amélioré"},{"name":"Fouloir amélioré"},{"name":"Ventilation améliorée"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Surdité","priority":3}],"consumables":["Grande trousse x2","Grande réparation","Extincteur automatique"],"do_list":["Jouer en support des pushes, pas en pointe.","Viser les zones faibles des ennemis.","Profiter de l'alpha pour sortir les cibles affaiblies."],"dont_list":["Exposer ton hull à des TDs ou chars précis.","Aller seul en éclaireur."],"tags":["siège","alpha","masse","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"maus","name":"Maus","nation":"allemagne","tier":10,"class":"HT","clan_priority":"situationnel","modes":["bastion","peloton"],"role_in_battle":"Anchor / Wall","gameplay_type":"Défensif pur — bouclier pour les alliés","summary":"Tank le plus lourd du jeu. Pratiquement impossible à tuer rapidement. Utile en bastion sur certaines cartes pour bloquer un couloir ou absorber tous les dégâts. Trop lent pour la CW moderne.","equipments":[{"name":"Durcissement amélioré"},{"name":"Fouloir amélioré"},{"name":"Ventilation améliorée"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2}],"consumables":["Grande trousse x2","Extincteur automatique","Grande réparation"],"do_list":["Bloquer un couloir complet pour les alliés.","Absorber un maximum de dégâts.","Tenir une position statique clé."],"dont_list":["Essayer de faire des rotations rapides.","Jouer sur des cartes ouvertes — il est une cible fixe pour les TDs."],"tags":["anchor","wall","lent","blindage","situationnel","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"strv-103b","name":"Strv 103B","nation":"suede","tier":10,"class":"TD","clan_priority":"prioritaire","modes":["cw","bastion","offensive"],"role_in_battle":"TD sniper / Counter push","gameplay_type":"Snipe défensif — tuer à distance, repositionnement rapide","summary":"TD unique sans tourelle. Impossible à pénétrer de face en position de tir. Utilisé pour contrôler les distances, punir les chars qui avancent, et couvrir les flancs depuis des positions élevées.","equipments":[{"name":"Optique de combat"},{"name":"Visée renforcée"},{"name":"Ventilation améliorée"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Camouflage","priority":2},{"name":"Précision (commandant)","priority":3},{"name":"Réparations","priority":4}],"consumables":["Grande trousse","Grande réparation","Optique de camouflage"],"do_list":["Prendre les positions élevées avec ligne de vue dégagée.","Ne jamais exposer son flanc.","Se repositionner après 2-3 tirs pour éviter le counter.","Punir les tanks qui push à découvert."],"dont_list":["Engager à courte distance.","Rester sur la même position trop longtemps.","Avancer au contact — tu n'as pas de tourelle."],"tags":["sniper","camouflage","TD","distance","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"vz-55","name":"Vz. 55","nation":"tcheque","tier":10,"class":"HT","clan_priority":"prioritaire","modes":["cw","bastion","offensive","peloton"],"role_in_battle":"Heavy autoloader / Burst damage","gameplay_type":"Agressif — deux tirs rapides, pression burst","summary":"Autoloader à 2 obus avec rechargement entre obus de 3s. Peut infliger 700 DPM en rafale en quelques secondes. Idéal pour achever une cible ou créer une pression burst décisive.","equipments":[{"name":"Stabilisateur vertical"},{"name":"Fouloir amélioré"},{"name":"Durcissement amélioré"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2},{"name":"Précision","priority":3}],"consumables":["Grande trousse","Grande réparation","Essence 100 octanes"],"do_list":["Vider le chargeur sur une cible affaiblie.","Garder les 2 obus pour une cible prioritaire annoncée par le caller.","Recharger en sécurité — ton rechargement complet est long."],"dont_list":["Gaspiller les obus au début de la partie.","Engager des chars pleins HP seul.","Rester visible pendant le rechargement."],"tags":["autoloader","burst","deux-obus","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"bz-75","name":"BZ-75","nation":"chine","tier":10,"class":"HT","clan_priority":"utile","modes":["cw","bastion","peloton"],"role_in_battle":"Heavy assault / Rocket boosted push","gameplay_type":"Agressif — charges rapides et pression frontale","summary":"Heavy unique avec des boosters de roquette permettant des accélérations rapides. Excellent pour les départs rapides et les pushes surprise. Son blindage de caisse frontal est très solide.","equipments":[{"name":"Durcissement amélioré"},{"name":"Fouloir amélioré"},{"name":"Stabilisateur vertical"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Réparations","priority":2}],"consumables":["Grande trousse","Grande réparation","Extincteur automatique"],"do_list":["Utiliser les boosters pour les positions prioritaires en début de game.","Push avec couverture allié.","Absorber les dégâts pour les alliés plus fragiles."],"dont_list":["Utiliser les boosters sans objectif précis.","Engager seul sans soutien."],"tags":["boost","push","assault","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"leopard-1","name":"Leopard 1","nation":"allemagne","tier":10,"class":"MT","clan_priority":"utile","modes":["cw","bastion","peloton","random"],"role_in_battle":"Medium sniper / Support feu longue portée","gameplay_type":"Précision à longue distance — hit and repositionnement","summary":"Précision exceptionnelle et grand canon. Joue le rôle de sniper de support depuis les flancs ou les positions élevées. Peu de blindage donc évite les confrontations directes.","equipments":[{"name":"Visée renforcée","reason":"Précision maximale à longue portée"},{"name":"Stabilisateur vertical"},{"name":"Ventilation améliorée"}],"crew_skills":[{"name":"Frères d'armes","priority":1},{"name":"Précision (commandant)","priority":2},{"name":"Camouflage","priority":3}],"consumables":["Grande trousse","Grande réparation","Optique de camouflage"],"do_list":["Prendre des positions avec bonne ligne de vue.","Tirer puis se déplacer immédiatement.","Punir les cibles exposées à longue portée."],"dont_list":["Engager à courte distance — ton blindage est quasi nul.","Tenir une position fixe trop longtemps."],"tags":["sniper","précision","medium","longue-portée","tier10"],"validated_by":"Staff ATFR","updated_at":"Juin 2026"},{"slug":"tvp-t-50-51","name":"TVP T 50/51","nation":"tcheque","tier":10,"class":"MT","clan_priority":"utile","modes":["cw","bastion","peloton","random"],"role_in_battle":"Medium autoloader / Burst damage rapide","gameplay_type":"Burst puis repositionnement — 4 obus en rafale","summary":"Autoloader à 4 obus. Peut infliger 1320 HP en rafale. Utilisé pour finir des batailles, clear des flancs ou punir des chars exposés. Rechargement inter-obus très rapide.","equipments":[{"name":"Stabilisateur vertical"},{"name":"Fouloir amélioré"}